window.PACTO.acts["reg-2009-810"]={"label": "REGOLAMENTO (CE) N. 810/2009 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 810/2009", "file": "ext-reg-2009-810.html", "external": true, "version": "consolidato 2024-06-28", "eurlex": "https://eur-lex.europa.eu/eli/reg/2009/810/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Obiettivo e ambito d’applicazione", "anchor": "art_1", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento stabilisce le procedure e le condizioni per il rilascio dei visti per soggiorni previsti nel territorio degli Stati membri non superiori a 90 giorni su un periodo di 180 giorni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le disposizioni del presente regolamento si applicano ai cittadini di paesi terzi che devono essere in possesso di un visto all’atto dell’attraversamento delle frontiere esterne degli Stati membri in conformità del regolamento (CE) n. 539/2001 del Consiglio, del 15 marzo 2001, che adotta l’elenco dei paesi terzi i cui cittadini devono essere in possesso del visto all’atto dell’attraversamento delle frontiere esterne e l’elenco dei paesi terzi i cui cittadini sono esenti da tale obbligo (\n<span class=\"superscript\">1</span>\n), fermi restando:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti di libera circolazione di cui godono i cittadini di paesi terzi che sono familiari di cittadini dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti di libera circolazione equivalenti a quelli dei cittadini dell’Unione e dei loro familiari, di cui godono cittadini di paesi terzi e loro familiari in virtù di accordi fra la Comunità e i suoi Stati membri, da un lato, e tali paesi terzi, dall’altro;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti di soggiorno di cui godono nello Stato ospitante, quale definito nell’accordo sul recesso del Regno Unito di Gran Bretagna e Irlanda del Nord dall’Unione europea e dalla Comunità europea dell’energia atomica (\n<span class=\"superscript\">2</span>\n) («accordo di recesso UE-Regno Unito»), i cittadini di paesi terzi che sono familiari di cittadini del Regno Unito beneficiari di tale accordo.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presente regolamento elenca anche i paesi terzi i cui cittadini sono soggetti all’obbligo di un visto di transito aeroportuale in deroga al principio di libero transito stabilito dall’allegato 9 della convenzione di Chicago relativa all’aviazione civile internazionale e definisce le procedure e le condizioni per il rilascio del visto ai fini del transito nelle zone di transito internazionali degli aeroporti degli Stati membri.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In sede di applicazione del presente regolamento, gli Stati membri agiscono nel pieno rispetto del diritto unionale, compresa la Carta dei diritti fondamentali dell'Unione europea. Conformemente ai principi generali del diritto unionale, le decisioni sulle domande ai sensi del presente regolamento sono adottate su base individuale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le seguenti definizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadino di paesi terzi»: chi non è cittadino dell’Unione ai sensi dell’articolo 17, paragrafo 1, del trattato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«visto»: autorizzazione rilasciata da uno Stato membro, necessaria ai fini:</p>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di un soggiorno previsto nel territorio degli Stati membri non superiore a 90 giorni su un periodo di 180 giorni; o</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">del transito nelle zone internazionali degli aeroporti degli Stati membri;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«visto uniforme»: visto valido per l’intero territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«visto con validità territoriale limitata»: visto valido per il territorio di uno o più Stati membri ma non per tutti gli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«visto di transito aeroportuale»: visto valido per il transito nelle zone internazionali di transito di uno o più aeroporti degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«visto adesivo»: formato uniforme per i visti quale definito dal regolamento (CE) n. 1683/95 del Consiglio, del 29 maggio 1995, che istituisce un modello uniforme per i visti (\n<span class=\"superscript\">3</span>\n);</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«documento di viaggio riconosciuto»: documento di viaggio riconosciuto da uno o più Stati membri ai fini dell'attraversamento delle frontiere esterne e dell'apposizione del visto ai sensi della decisione n. 1105/2011/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n);</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«foglio separato per l’apposizione del visto»: modello uniforme di foglio utilizzabile per l’apposizione di un visto rilasciato dagli Stati membri a persone titolari di un documento di viaggio non riconosciuto dallo Stato membro che emette il foglio, ai sensi del regolamento (CE) n. 333/2002 del Consiglio, del 18 febbraio 2002, relativo ad un modello uniforme di foglio utilizzabile per l’apposizione di un visto rilasciato dagli Stati membri a persone titolari di un documento di viaggio non riconosciuto dallo Stato membro che emette il foglio (\n<span class=\"superscript\">5</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«consolato»: rappresentanza diplomatica o consolare di uno Stato membro, abilitata a rilasciare visti e diretta da un funzionario consolare di carriera, quale definita dalla convenzione di Vienna sulle relazioni consolari del 24 aprile 1963;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«domanda»: domanda di visto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«intermediari commerciali»: agenzie amministrative private, società di trasporto o agenzie di viaggio (operatori turistici o venditori);</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«marittimo»: ogni persona occupata, ingaggiata o che lavora a qualsiasi titolo a bordo di una nave in navigazione marittima o di una nave che opera in acque interne internazionali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«firma elettronica»: una firma elettronica quale definita all'articolo 3, punto 10, del regolamento (UE) n. 910/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n).</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Cittadini di paesi terzi che devono essere in possesso di un visto di transito aeroportuale", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I cittadini dei paesi terzi figuranti nell’elenco di cui all’allegato IV devono essere in possesso di un visto di transito aeroportuale per il transito nelle zone internazionali degli aeroporti situati sul territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In casi urgenti di afflusso massiccio di immigrati illegali, singoli Stati membri possono richiedere ai cittadini di paesi terzi diversi da quelli di cui al paragrafo 1 di essere in possesso di un visto di transito aeroportuale per il transito nelle zone internazionali degli aeroporti situati sul loro territorio. Gli Stati membri comunicano alla Commissione tali decisioni prima della relativa entrata in vigore nonché la revoca dell’obbligo del visto di transito aeroportuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’ambito del comitato di cui all’articolo 52, paragrafo 1, tali comunicazioni sono riesaminate annualmente allo scopo di trasferire il paese terzo interessato nell’elenco di cui all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il paese terzo non è trasferito nell’elenco di cui all’allegato IV, lo Stato membro interessato, purché le condizioni di cui al paragrafo 2 siano soddisfatte, può mantenere o revocare l’obbligo del visto di transito aeroportuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono esentate dall’obbligo di essere in possesso di un visto di transito aeroportuale ai sensi dei paragrafi 1 e 2 le seguenti categorie di persone:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titolari di un visto uniforme valido, di un visto nazionale per soggiorno di lunga durata o di un titolo di soggiorno rilasciato da uno Stato membro;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi titolari di un titolo di soggiorno valido rilasciato da uno Stato membro che non partecipa all’adozione del presente regolamento o da uno Stato membro che non applica ancora pienamente le disposizioni dell’acquis di Schengen e i cittadini di paesi terzi titolari di uno dei titoli di soggiorno validi menzionati nell’allegato V, rilasciati da Andorra, dal Canada, dal Giappone, da San Marino, dal Regno Unito o dagli Stati Uniti d’America, che garantisca il ritorno incondizionato del titolare, o titolari di un permesso di soggiorno valido per uno o più paesi e territori d’oltremare del Regno dei Paesi Bassi (Aruba, Curaçao, Sint Maarten, Bonaire, Sint Eustatius e Saba);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼C3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi titolari di un visto valido per uno Stato membro che non partecipa all’adozione del presente regolamento, per uno Stato membro che non applica ancora pienamente le disposizioni dell’<span class=\"italics\">acquis</span> di Schengen, o per il Canada, il Giappone o gli Stati Uniti d’America, o i titolari di un visto valido per uno o più paesi e territori d'oltremare del Regno dei Paesi Bassi (Aruba, Curaçao, Sint Maarten, Bonaire, Sint Eustatius e Saba), quando si recano nel paese di rilascio o in un altro paese terzo, o quando, dopo aver utilizzato tale visto, ritornano dal paese di rilascio;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M6\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i familiari di cittadini dell’Unione di cui all’articolo 1, paragrafo 2, lettera a), i familiari di cittadini di paesi terzi di cui all’articolo 1, paragrafo 2, lettera b), e i familiari di cittadini del Regno Unito beneficiari dell’accordo di recesso UE-Regno Unito di cui all’articolo 1, paragrafo 2, lettera c);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titolari di passaporti diplomatici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i membri dell’equipaggio di aerei che sono cittadini di una parte contraente della convenzione di Chicago relativa all’aviazione civile internazionale.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Autorità competenti interessate dalle procedure connesse alle domande", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le domande sono esaminate dai consolati, i quali decidono sul merito.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, gli Stati membri possono decidere che le domande sono esaminate dalle autorità centrali, le quali decidono in merito. Gli Stati membri provvedono affinché tali autorità abbiano una conoscenza sufficiente delle circostanze locali del paese in cui è presentata la domanda al fine di valutare i rischi migratori e per la sicurezza e una conoscenza sufficiente della lingua ai fini dell'analisi dei documenti, e provvedono inoltre affinché i consolati siano coinvolti, ove necessario, al fine di procedere a esami e colloqui aggiuntivi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, le domande possono essere esaminate alle frontiere esterne degli Stati membri dalle autorità responsabili dei controlli sulle persone a norma dell’articolo 35 e dell’articolo 36, le quali decidono sul merito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei territori d’oltremare non europei degli Stati membri, le domande possono essere esaminate dalle autorità designate dallo Stato membro interessato, le quali decidono sul merito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può chiedere di coinvolgere autorità diverse da quelle designate ai paragrafi 1 e 2 nell’esame delle domande e nelle decisioni sul merito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può chiedere di essere consultato o informato da un altro Stato membro a norma degli articoli 22 e 31.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Stato membro competente per l’esame delle domande e per le decisioni sul merito", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro competente per l’esame di una domanda di visto uniforme e per la decisione sul merito è:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro il cui territorio costituisce l’unica destinazione del viaggio o dei viaggi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il viaggio comprende più di una destinazione, o se devono essere effettuati più viaggi separati nell'arco di due mesi, lo Stato membro il cui territorio costituisce la destinazione principale del o dei viaggi in termini di durata, calcolata in giorni, o di finalità del soggiorno; oppure</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora non possa essere determinata la destinazione principale, lo Stato membro attraverso le cui frontiere esterne il richiedente intende entrare nel territorio degli Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro competente per l’esame di una domanda di visto uniforme ai fini del transito e per la decisione sul merito è:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di transito attraverso un solo Stato membro, lo Stato membro interessato; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di transito attraverso più Stati membri, lo Stato membro attraverso le cui frontiere esterne il richiedente intende cominciare il transito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro competente per l’esame di una domanda di visto di transito aeroportuale e per la decisione sul merito è:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di un singolo transito aeroportuale, lo Stato membro nel cui territorio è situato l’aeroporto di transito; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di transito aeroportuale, duplice o multiplo lo Stato membro nel cui territorio è situato l’aeroporto del primo transito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri cooperano per evitare situazioni in cui una domanda non possa formare oggetto di esame e di decisione qualora lo Stato membro competente ai sensi dei paragrafi da 1 a 3 non sia né presente né rappresentato nel paese terzo in cui il richiedente presenta la domanda a norma dell’articolo 6.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Competenza territoriale consolare", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una domanda è esaminata e la decisione sul merito è presa dal consolato dello Stato membro competente nella cui giurisdizione il richiedente risiede legalmente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Un consolato dello Stato membro competente esamina e decide in merito a una domanda di un cittadino di un paese terzo presente legalmente ma non residente nella sua giurisdizione se il richiedente ha giustificato la domanda presso detto consolato.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Competenza a rilasciare visti a cittadini di paesi terzi legalmente presenti nel territorio di uno Stato membro", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">I cittadini di paesi terzi legalmente presenti nel territorio di uno Stato membro e che devono essere in possesso di un visto per entrare nel territorio di uno o più altri Stati membri presentano la domanda presso il consolato dello Stato membro competente ai sensi dell’articolo 5, paragrafi 1 o 2.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Accordi di rappresentanza", "anchor": "art_8", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può accettare di rappresentare un altro Stato membro che sia competente ai sensi dell'articolo 5 ai fini dell'esame e delle decisioni riguardo alle domande per conto di tale Stato membro. Uno Stato membro può anche rappresentare un altro Stato membro in modo limitato soltanto per la raccolta delle domande e il rilevamento degli identificatori biometrici.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se la rappresentanza si limita conformemente al paragrafo 1, seconda frase, alla raccolta e alla trasmissione dei dati allo Stato membro rappresentato si effettuano nel rispetto delle pertinenti norme in materia di protezione dei dati e di sicurezza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tra lo Stato membro rappresentante e lo Stato membro rappresentato è stabilito un accordo bilaterale. Tale accordo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specifica la durata della rappresentanza, se temporanea, e le modalità di cessazione della stessa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">può, in particolare qualora lo Stato membro rappresentato abbia un consolato nel paese terzo interessato, prevedere la messa a disposizione di locali e personale e il versamento di un corrispettivo da parte dello Stato membro rappresentato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che non hanno un proprio consolato in un paese terzo si adoperano per concludere accordi di rappresentanza con Stati membri che hanno consolati in tale paese.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Per evitare che un’infrastruttura di trasporto carente o lunghe distanze in una regione o area geografica specifica richiedano uno sforzo sproporzionato da parte dei richiedenti per avere accesso a un consolato, gli Stati membri che non hanno una proprio consolato in tale regione o area si adoperano per concludere accordi di rappresentanza con Stati membri che hanno consolati in quella regione o area.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rappresentato notifica alla Commissione gli accordi di rappresentanza o la loro cessazione almeno 20 giorni di calendario prima della loro entrata in vigore o cessazione, tranne in caso di forza maggiore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Contemporaneamente alla notifica di cui al paragrafo 7, il consolato dello Stato membro rappresentante informa sia i consolati degli altri Stati membri sia la delegazione dell'Unione nella giurisdizione interessata degli accordi di rappresentanza o della loro cessazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Se il consolato dello Stato membro rappresentante decide di cooperare con un fornitore esterno di servizi, conformemente all’articolo 43, o con intermediari commerciali accreditati, come previsto all’articolo 45, tale cooperazione include le domande contemplate dagli accordi di rappresentanza. Le autorità centrali dello Stato membro rappresentato sono informate in anticipo dei termini di tale cooperazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro non è né presente né rappresentato nel paese terzo in cui il richiedente intende presentare la domanda, detto Stato membro si adopera per cooperare con un fornitore esterno di servizi, conformemente all'articolo 43, in tale paese terzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Qualora un consolato di uno Stato membro in un dato luogo subisca una prolungata forza maggiore per problemi di natura tecnica, tale Stato membro chiede di essere temporaneamente rappresentato da un altro Stato membro in detto luogo per alcune o tutte le categorie di richiedenti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Modalità pratiche per la presentazione delle domande", "anchor": "art_9", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le domande sono presentate non più di sei mesi o, per i marittimi nell'espletamento delle loro mansioni, non più di nove mesi prima dell'inizio del viaggio previsto e, di norma, al più tardi 15 giorni di calendario prima dell'inizio del viaggio previsto. In singoli casi d'urgenza giustificati, il consolato o le autorità centrali possono permettere che le domande siano presentate meno di 15 giorni di calendario prima dell'inizio del viaggio previsto.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I richiedenti possono essere tenuti a chiedere un appuntamento per la presentazione della domanda. L’appuntamento ha luogo, di norma, entro due settimane dalla data della richiesta di appuntamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In giustificati casi d’urgenza il consolato può autorizzare i richiedenti a presentare domande senza chiedere l’appuntamento, o tale appuntamento è dato immediatamente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ferme restando le disposizioni di cui all'articolo 13, le domande possono essere presentate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dal richiedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da un intermediario commerciale accreditato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da un'associazione o istituzione professionale, culturale, sportiva o d'istruzione, per conto dei suoi membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il richiedente non può essere obbligato a presentarsi di persona in più di una sede per presentare una domanda.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "10": {"label": "Articolo 10", "heading": "Norme generali per la presentazione delle domande", "anchor": "art_10", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I richiedenti si presentano di persona per la presentazione della domanda ai fini del rilevamento delle impronte digitali, in conformità dell'articolo 13, paragrafi 2 e 3, e paragrafo 7, lettera b). Fatto salvo quanto disposto alla prima frase del presente paragrafo e all'articolo 45, i richiedenti hanno la facoltà di presentare le loro domande elettronicamente, ove possibile.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel presentare la domanda, il richiedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un modulo di domanda ai sensi dell’articolo 11;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un documento di viaggio ai sensi dell’articolo 12;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta una fotografia conformemente alle norme stabilite nel regolamento (CE) n. 1683/95 o, quando il VIS è operativo a norma dell’articolo 48 del regolamento VIS, conformemente alle norme di cui all’articolo 13 del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consente il rilevamento delle proprie impronte digitali conformemente all’articolo 13, ove applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paga i diritti di visto ai sensi dell’articolo 16;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce documenti giustificativi, conformemente all’articolo 14 e all’allegato II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove applicabile, dimostra di possedere un’adeguata e valida assicurazione sanitaria di viaggio conformemente all’articolo 15.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Moduli di domanda", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">\n<span>\n<span class=\"boldface\">►M5</span>\n</span> 1.  </span>\n<div class=\"norm inline-element\">Ogni richiedente presenta un modulo di domanda di cui all'allegato I compilato manualmente o elettronicamente. Il modulo di domanda deve essere firmato. Può essere firmato manualmente o, qualora la firma elettronica sia riconosciuta dallo Stato membro competente per l'esame della domanda e per la decisione in merito, elettronicamente.<span class=\"boldface\"> ◄ </span> Le persone figuranti sul documento di viaggio del richiedente presentano moduli di domanda separati. I minori presentano un modulo di domanda firmato da una persona che esercita la potestà genitoriale permanente o temporanea o da un tutore legale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">Qualora il richiedente firmi un modulo di domanda elettronicamente, la firma elettronica deve essere una firma elettronica qualificata ai sensi dell'articolo 3, punto 12, del regolamento (UE) n. 910/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 ter.  </span>\n<div class=\"norm inline-element\">Il contenuto della versione elettronica del modulo di domanda, ove applicabile, è conforme al modello di cui all'allegato I.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I consolati fanno sì che i moduli di domanda siano ampiamente disponibili e facilmente accessibili ai richiedenti a titolo gratuito.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I moduli sono disponibili come minimo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nelle lingue ufficiali dello Stato membro per il quale è richiesto il visto o dello Stato membro rappresentante; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nelle lingue ufficiali del paese ospitante.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Oltre che nelle lingue di cui alla lettera a), il modulo può essere reso disponibile in un'altra lingua ufficiale delle istituzioni dell'Unione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se le lingue ufficiali del paese ospitante non figurano nel modulo, è resa disponibile separatamente ai richiedenti una traduzione in tali lingue.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Una traduzione del modulo di domanda nelle lingue ufficiali del paese ospitante è fornita nell’ambito della cooperazione locale Schengen di cui all’articolo 48.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il consolato informa i richiedenti in merito alle lingue utilizzabili per compilare il modulo di domanda.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Documento di viaggio", "anchor": "art_12", "frags": [[null, "<p class=\"norm\">Il richiedente presenta un documento di viaggio valido che soddisfi i seguenti criteri:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la validità è di almeno tre mesi dopo la data prevista per la partenza dal territorio degli Stati membri o, in caso di più viaggi, dopo l’ultima data prevista per la partenza dal territorio degli Stati membri. Tuttavia, in casi di emergenza giustificati, è possibile derogare a tale obbligo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contiene almeno due pagine bianche;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato rilasciato nel corso dei dieci anni precedenti.</p>\n</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Identificatori biometrici", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri rilevano gli identificatori biometrici del richiedente comprendenti una fotografia e le impronte delle dieci dita dello stesso, conformemente alle garanzie previste dalla convenzione del Consiglio d’Europa per la salvaguardia dei diritti dell’uomo e delle libertà fondamentali, dalla Carta dei diritti fondamentali dell’Unione europea e dalla convenzione delle Nazioni Unite sui diritti del fanciullo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il richiedente che introduce la prima domanda deve presentarsi di persona. In tale occasione sono rilevati i seguenti identificatori biometrici del richiedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">una fotografia, scansionata o fatta al momento della domanda, e</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le sue impronte delle dieci dita prese a dita piatte, rilevate digitalmente.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se le impronte digitali del richiedente rilevate nell’ambito di una domanda precedente sono inserite nel VIS per la prima volta meno di cinquantanove mesi prima della data della nuova domanda, esse sono copiate nella domanda successiva.</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, in caso di dubbi ragionevoli sull’identità del richiedente, il consolato rileva le impronte digitali entro il termine di cui al primo comma.</p>"], [null, "<p class=\"norm\">Inoltre, se al momento della presentazione della domanda non può essere confermato immediatamente che le impronte digitali sono state rilevate entro il termine di cui al primo comma, il richiedente può chiedere che siano rilevate.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> A norma dell’articolo 9, punto 5), del regolamento VIS, la fotografia allegata a ogni domanda è inserita nel VIS.<span class=\"boldface\"> ◄ </span> Non è necessario che il richiedente si presenti di persona a tal fine.</div>\n</div>"], [null, "<p class=\"norm\">I requisiti tecnici della fotografia sono conformi alle norme internazionali di cui al documento n. 9303, parte 1, 6<span class=\"superscript\">a</span> edizione dell’Organizzazione dell’aviazione civile internazionale (ICAO).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le impronte digitali sono rilevate conformemente alle norme ICAO e alla decisione 2006/648/CE della Commissione, del 22 settembre 2006, che stabilisce le specifiche tecniche in relazione alle norme sulle caratteristiche biometriche per lo sviluppo del Sistema informazione visti (\n<span class=\"superscript\">7</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli identificatori biometrici sono rilevati da personale qualificato e debitamente autorizzato delle autorità competenti a norma dell’articolo 4, paragrafi 1, 2 e 3. Sotto la supervisione dei consolati, gli identificatori biometrici possono essere rilevati anche da personale qualificato e debitamente autorizzato del console onorario di cui all’articolo 42 o di un fornitore esterno di servizi di cui all’articolo 43. Lo Stato membro o gli Stati membri interessati, in caso di dubbi, prevedono la possibilità di verificare presso il consolato le impronte digitali che sono state rilevate dal fornitore esterno di servizi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono esentati dall’obbligo di rilevamento delle impronte digitali i seguenti richiedenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">bambini di età inferiore a dodici anni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone per le quali è fisicamente impossibile rilevarle. Se tuttavia è possibile rilevare un numero di impronte digitali inferiore a dieci, si procede al rilevamento del numero massimo di impronte. Tuttavia, qualora l’impossibilità sia temporanea, il richiedente è invitato a fornire le impronte digitali in occasione della domanda successiva. Le autorità competenti a norma dell’articolo 4, paragrafi 1, 2 e 3, sono autorizzate a chiedere ulteriori chiarimenti dei motivi dell’impossibilità temporanea. Gli Stati membri provvedono affinché siano predisposte procedure idonee a garanzia della dignità del richiedente in caso di difficoltà nel rilevamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">capi di Stato o di governo e membri dei governi nazionali, accompagnati dai consorti, e membri della loro delegazione ufficiale quando sono invitati dai governi degli Stati membri o da organizzazioni internazionali in missione ufficiale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sovrani e altri importanti membri di una famiglia reale quando sono invitati dai governi degli Stati membri o da organizzazioni internazionali in missione ufficiale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Nei casi di cui al paragrafo 7, va inserita nel VIS la menzione «non applicabile» a norma dell’articolo 8, paragrafo 5, del regolamento VIS.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Documenti giustificativi", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">All’atto della presentazione di una domanda di visto uniforme il richiedente presenta:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti che indichino la finalità del viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti relativi all’alloggio, o prova della disponibilità di mezzi sufficienti per l’alloggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti che indichino che il richiedente dispone dei mezzi di sussistenza sufficienti, sia per la durata prevista del soggiorno, sia per il ritorno nel paese di origine o di residenza, o per il transito verso un paese terzo nel quale l’ammissione è garantita, ovvero è in grado di ottenere legalmente detti mezzi, a norma dell’articolo 5, paragrafo 1, lettera c), e paragrafo 3 del codice frontiere Schengen;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni che consentano di valutare l’intenzione del richiedente di lasciare il territorio degli Stati membri prima della scadenza del visto richiesto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">All’atto della presentazione di una domanda di visto di transito aeroportuale il richiedente presenta:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documenti relativi al proseguimento del viaggio verso la destinazione finale dopo il transito aeroportuale previsto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni che consentano di valutare l’intenzione del richiedente di non entrare nel territorio degli Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Un elenco non esaustivo di documenti giustificativi che possono essere chiesti al richiedente per verificare che soddisfi le condizioni di cui ai paragrafi 1 e 2 figura nell'allegato II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono chiedere al richiedente di presentare una dichiarazione di garanzia o una dichiarazione di alloggio da parte di un privato, o entrambe, compilando un modulo elaborato da ciascuno Stato membro. Tale modulo indica in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è inteso come dichiarazione di garanzia o dichiarazione di alloggio privato, o entrambe;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il garante o la persona che invita è una persona fisica, una società o un'organizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'identità e gli estremi del garante o della persona che invita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati relativi all'identità (nome e cognome, data di nascita, luogo di nascita e cittadinanza) del richiedente o dei richiedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'indirizzo dell'alloggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la durata e la finalità del soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli eventuali legami di parentela con il garante o la persona che invita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni richieste ai sensi dell'articolo 37, paragrafo 1, del regolamento VIS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il modulo è redatto nelle lingue ufficiali dello Stato membro e in almeno un'altra lingua ufficiale delle istituzioni dell'Unione. Un facsimile del modulo è inviato alla Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I consolati, nell'ambito della cooperazione locale Schengen, valutano l'applicazione delle condizioni di cui al paragrafo 1, per tenere conto delle circostanze locali e dei rischi migratori e per la sicurezza.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5 bis.  </span>\n<div class=\"norm inline-element\">Se necessario per tenere conto delle circostanze locali conformemente all'articolo 48, la Commissione adotta mediante atti di esecuzione un elenco armonizzato di documenti giustificativi da usare in ciascuna giurisdizione. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 52, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">È possibile derogare ai requisiti di cui al paragrafo 1 del presente articolo nel caso di un richiedente noto al consolato o alle autorità centrali per integrità e affidabilità, in particolare per quanto riguarda la correttezza nell'uso di precedenti visti, qualora non vi sia alcun dubbio riguardo al fatto che il richiedente soddisfi i requisiti di cui all'articolo 6, paragrafo 1, del regolamento (UE) 2016/399 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">8</span>\n) all'atto dell'attraversamento delle frontiere esterne degli Stati membri.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "15": {"label": "Articolo 15", "heading": "Assicurazione sanitaria di viaggio", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I richiedenti i visti uniformi per uno o due ingressi devono dimostrare di possedere un’adeguata e valida assicurazione sanitaria di viaggio che copra le spese che potrebbero rendersi necessarie per il rimpatrio dovuto a motivi di salute, cure mediche urgenti, ricoveri ospedalieri d’urgenza o morte durante il loro soggiorno o i loro soggiorni nel territorio degli Stati membri.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I richiedenti i visti per ingressi multipli devono dimostrare di possedere un'adeguata e valida assicurazione sanitaria di viaggio che copra il periodo del primo viaggio previsto.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Dovranno inoltre firmare la dichiarazione, figurante nel modulo di domanda, con la quale affermano di essere consapevoli della necessità di avere un’assicurazione sanitaria di viaggio per i soggiorni successivi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assicurazione è valida per l’insieme del territorio degli Stati membri e copre il periodo complessivo di soggiorno o di transito previsto dell’interessato. La copertura minima ammonta a 30 000  EUR.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di rilascio di un visto con validità territoriale limitata che copre il territorio di più di uno Stato membro, la copertura assicurativa è valida almeno negli Stati membri interessati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I richiedenti sottoscrivono, in linea di principio, l’assicurazione nel paese di residenza. Qualora ciò non sia possibile essi cercano di contrarre un’assicurazione in qualsiasi altro paese.</div>\n</div>"], [null, "<p class=\"norm\">Se un’altra persona contrae un’assicurazione a nome del richiedente, si applicano le condizioni di cui al paragrafo 3.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nel valutare l’adeguatezza della copertura assicurativa, i consolati accertano se le richieste di indennizzo nei confronti della compagnia di assicurazione siano riscuotibili negli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’obbligo di sottoscrivere l’assicurazione può essere considerato come soddisfatto qualora si accerti che una copertura assicurativa adeguata è presumibile alla luce della situazione professionale del richiedente. L’esonero dalla dimostrazione di essere in possesso di un’assicurazione sanitaria di viaggio può interessare determinati gruppi professionali, quali i marittimi, già coperti da un’assicurazione sanitaria di viaggio per le loro attività professionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I titolari di passaporti diplomatici sono esentati dall’obbligo di possedere un’assicurazione sanitaria di viaggio.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Diritti per i visti", "anchor": "art_16", "frags": [[null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I richiedenti pagano diritti pari a 90 EUR.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per i minori di età uguale o superiore a sei anni e inferiore a dodici anni i diritti per i visti ammontano a 45 EUR.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2<span class=\"italics\">bis</span>  </span>\n<div class=\"norm inline-element\">Se una decisione di esecuzione è adottata dal Consiglio in conformità dell’articolo 25 <span class=\"italics\">bis</span>, paragrafo 5, lettera b), si applicano diritti per i visti pari a 135 EUR o 180 EUR. La presente disposizione non si applica ai minori di età inferiore a dodici anni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I diritti per i visti non vengono riscossi per i richiedenti appartenenti a una delle categorie seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">minori di età inferiore ai sei anni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alunni, studenti, studenti già laureati e insegnanti accompagnatori che intraprendono soggiorni per motivi di studio o formazione pedagogica;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ricercatori, quali definiti all'articolo 3, punto 2, della direttiva (UE) 2016/801 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">9</span>\n), che si spostano a fini di ricerca scientifica o che partecipano a seminari o conferenze scientifici;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rappresentanti di organizzazioni senza fini di lucro di età non superiore ai venticinque anni che partecipano a seminari, conferenze, manifestazioni sportive, culturali o educative organizzati da organizzazioni senza fini di lucro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Possono essere esentati dal pagamento di diritti per il visto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i minori tra i sei e i diciotto anni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titolari di passaporti diplomatici e di servizio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i partecipanti a seminari, conferenze, manifestazioni sportive, culturali o educative organizzati da organizzazioni senza fini di lucro di età non superiore ai 25 anni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In singoli casi è possibile derogare alla riscossione o ridurre l'importo dei diritti per i visti, quando ciò serve a promuovere gli interessi culturali o sportivi, gli interessi in materia di politica estera, di politica dello sviluppo e di altri settori essenziali d'interesse pubblico, o per motivi umanitari o in virtù di obblighi internazionali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I diritti per i visti sono riscossi in euro, nella valuta nazionale del paese terzo o nella valuta solitamente utilizzata nel paese terzo ove è presentata la domanda e non sono rimborsabili, tranne nei casi di cui all’articolo 18, paragrafo 2, e all’articolo 19, paragrafo 3.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">Se riscosso in una valuta diversa dall'euro, l'importo dei diritti per i visti riscosso in tale valuta è determinato e riveduto periodicamente applicando il tasso di cambio di riferimento dell'euro fissato dalla Banca centrale europea. L'importo riscosso può essere arrotondato e deve essere assicurato, nell'ambito della cooperazione locale Schengen, che siano riscossi diritti simili.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Per tale pagamento il richiedente ottiene una ricevuta.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Ogni tre anni la Commissione valuta l'esigenza di rivedere l'importo dei diritti per i visti di cui ai paragrafi 1, 2 e 2 bis del presente articolo, tenendo conto di criteri obiettivi quali il tasso d'inflazione generale a livello dell'Unione pubblicato da Eurostat e la media ponderata delle retribuzioni dei funzionari degli Stati membri. Sulla base di tali valutazioni, la Commissione adotta, se opportuno e conformemente all'articolo 51 bis, atti relativi alla modifica del presente regolamento per quanto riguarda l'importo dei diritti per i visti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "17": {"label": "Articolo 17", "heading": "Diritti per servizi prestati", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">\n<span>\n<span class=\"boldface\">►M5</span>\n</span> 1.  </span>\n<div class=\"norm inline-element\">Il fornitore esterno di servizi di cui all'articolo 43 può chiedere il pagamento di diritti per servizi prestati.<span class=\"boldface\"> ◄ </span> I diritti per servizi prestati sono proporzionali alle spese sostenute dal fornitore esterno di servizi nello svolgere uno o più dei compiti di cui all’articolo 43, paragrafo 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo dei diritti per servizi prestati è precisato nello strumento giuridico di cui all’articolo 43, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tale importo non supera la metà dell’importo del diritto per il visto di cui all’articolo 16, paragrafo 1, indipendentemente dalle eventuali riduzioni o deroghe ai diritti per i visti di cui all’articolo 16, paragrafi 2, 4, 5 e 6.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 bis.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 4, i diritti per servizi prestati non superano, in linea di principio, 80 EUR nei paesi terzi in cui lo Stato membro competente non abbia un consolato ai fini della raccolta delle domande e non sia rappresentato da un altro Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 ter.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali in cui l'importo di cui al paragrafo 4 bis non è sufficiente per fornire un servizio completo, è possibile imporre diritti per servizi prestati più elevati fino a un massimo di 120 EUR. In tal caso, lo Stato membro interessato notifica alla Commissione la sua intenzione di consentire l'imposizione di diritti per servizi prestati più elevati al più tardi tre mesi prima dell'inizio della loro applicazione. La notifica precisa i motivi alla base della determinazione del livello dei diritti per servizi prestati, in particolare i costi dettagliati che hanno portato alla determinazione di un importo più elevato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro interessato può mantenere la possibilità per tutti i richiedenti di presentare la loro domanda direttamente ai rispettivi consolati o al consolato di uno Stato membro con cui ha un accordo di rappresentanza conformemente all'articolo 8.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "18": {"label": "Articolo 18", "heading": "Accertamento della competenza consolare", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando è presentata una domanda, il consolato verifica la propria competenza a esaminarla e a decidere sul merito alla stessa a norma degli articoli 5 e 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il consolato non è competente, restituisce senza indugio il modulo di domanda e tutti i documenti presentati dal richiedente, rimborsa i diritti per i visti e indica il consolato competente.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Ricevibilità", "anchor": "art_19", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consolato competente o le autorità centrali dello Stato membro competente verificano:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se la domanda è stata presentata entro il termine di cui all’articolo 9, paragrafo 1,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se la domanda contiene gli elementi di cui all’articolo 10, paragrafo 3, lettere da a) a c),</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se sono stati rilevati i dati biometrici del richiedente, e</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">se sono stati riscossi i diritti per i visti.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il consolato competente o le autorità centrali dello Stato membro competente constatano che le condizioni di cui al paragrafo 1 sono soddisfatte, la domanda è ricevibile e il consolato o le autorità centrali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">segue le procedure di cui all'articolo 8 del regolamento VIS, e</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">esamina ulteriormente la domanda.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼C2\n</p>"], [null, "<p class=\"norm\">I dati sono inseriti nel VIS soltanto da personale consolare debitamente autorizzato a norma dell’articolo 6, paragrafo 1, dell’articolo 7 e dell’articolo 9, punti 5) e 6), del regolamento VIS.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il consolato competente o le autorità centrali dello Stato membro competente constatano che le condizioni di cui al paragrafo 1 non sono soddisfatte, la domanda è irricevibile e il consolato o le autorità centrali, senza indugio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">restituisce il modulo di domanda e tutti i documenti presentati dal richiedente,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">distrugge i dati biometrici raccolti,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">rimborsa i diritti per i visti, e</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">non esamina la domanda.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A titolo di deroga del paragrafo 3, una domanda che non soddisfi i requisiti di cui al paragrafo 1 può essere considerata ricevibile per motivi umanitari o di interesse nazionale o in virtù di obblighi internazionali.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Verifica delle condizioni d’ingresso e valutazione del rischio", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’esaminare una domanda di visto uniforme viene accertato se il richiedente soddisfi le condizioni d’ingresso di cui all’articolo 5, paragrafo 1, lettere a), c), d) ed e), del codice frontiere Schengen ed è accordata particolare attenzione alla valutazione se il richiedente presenti un rischio di immigrazione illegale o un rischio per la sicurezza degli Stati membri e se il richiedente intenda lasciare il territorio degli Stati membri prima della scadenza del visto richiesto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per ciascuna domanda viene consultato il VIS conformemente all’articolo 8, paragrafo 2, e all’articolo 15 del regolamento VIS. Gli Stati membri provvedono affinché siano pienamente utilizzati tutti i criteri di ricerca di cui all’articolo 15 del regolamento VIS onde evitare respingimenti e identificazioni falsi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel determinare se il richiedente soddisfi le condizioni d'ingresso, il consolato o le autorità centrali verificano:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il documento di viaggio presentato non sia falso, contraffatto o alterato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la giustificazione presentata dal richiedente riguardo allo scopo e alle condizioni del soggiorno previsto e che questi disponga dei mezzi di sussistenza sufficienti, sia per la durata del soggiorno previsto sia per il ritorno nel paese di origine o di residenza oppure per il transito verso un paese terzo nel quale la sua ammissione è garantita, ovvero che sia in grado di ottenere legalmente detti mezzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è segnalato ai fini della non ammissione nel sistema d’informazione Schengen (SIS);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il richiedente non sia considerato una minaccia per l’ordine pubblico, la sicurezza interna o la salute pubblica, quale definita all’articolo 2, punto 19, del codice frontiere Schengen, o per le relazioni internazionali di uno degli Stati membri e, in particolare, che non sia oggetto di segnalazione ai fini della non ammissione nelle banche dati nazionali degli Stati membri per gli stessi motivi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il richiedente disponga di un'adeguata e valida assicurazione sanitaria di viaggio, ove applicabile, che copra il periodo del soggiorno previsto, oppure, se è chiesto un visto per ingressi multipli, il periodo del primo viaggio previsto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se del caso, il consolato o le autorità centrali verificano la durata dei soggiorni precedenti e previsti per accertare che il richiedente non abbia superato la durata massima del soggiorno autorizzato nel territorio degli Stati membri, indipendentemente da eventuali soggiorni autorizzati in base a un visto nazionale per soggiorno di lunga durata o a un titolo di soggiorno.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La valutazione dei mezzi di sussistenza per il soggiorno previsto si effettua in funzione della durata e dello scopo del soggiorno e con riferimento ai prezzi medi vigenti nello o negli Stati membri interessati per vitto e alloggio in sistemazione economica, moltiplicati per il numero di giorni del soggiorno, in base agli importi di riferimento fissati dagli Stati membri conformemente all’articolo 34, paragrafo 1, lettera c), del codice frontiere Schengen. La dichiarazione di garanzia e/o di alloggio da parte di un privato può altresì costituire una prova della disponibilità di mezzi di sussistenza sufficienti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In sede di esame di una domanda di visto di transito aeroportuale, il consolato o le autorità centrali verificano in particolare:</p>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il documento di viaggio presentato non sia falso, contraffatto o alterato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i luoghi di partenza e di destinazione del cittadino di paese terzo interessato e la coerenza dell’itinerario e del transito aeroportuale previsti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il giustificativo del proseguimento del viaggio verso la destinazione finale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’esame di una domanda si fonda, in particolare, sull’autenticità e l’affidabilità dei documenti presentati e sulla veridicità e l’affidabilità delle dichiarazioni fatte dal richiedente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Nel corso dell'esame di una domanda, i consolati o le autorità centrali possono, in casi giustificati, procedere a un colloquio con il richiedente e richiedere documenti supplementari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Un precedente rifiuto del visto non comporta il rifiuto automatico di una nuova domanda. Una nuova domanda è valutata sulla base di tutte le informazioni disponibili.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Consultazione preliminare delle autorità centrali degli altri Stati membri", "anchor": "art_22", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per motivi legati a una minaccia per l'ordine pubblico, la sicurezza interna, le relazioni internazionali o la salute pubblica, uno Stato membro può chiedere alle autorità centrali di altri Stati membri di consultare le proprie autorità centrali nel corso dell'esame delle domande presentate da cittadini di determinati paesi terzi o da specifiche categorie di tali cittadini. Tale consultazione non si applica alle domande di visto di transito aeroportuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità centrali consultate danno una risposta definitiva appena possibile e non oltre sette giorni di calendario dopo la consultazione. La mancanza di risposta entro tale termine implica che esse non hanno motivo di opporsi al rilascio del visto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione l'introduzione o il ritiro della richiesta di consultazione preliminare, di norma, almeno 25 giorni di calendario prima che detta misura diventi applicabile. Tale informazione è comunicata anche nell'ambito della cooperazione locale Schengen all'interno della giurisdizione interessata.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione informa gli Stati membri di tali notifiche.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Decisione sulla domanda", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La decisione sulla domanda è presa entro quindici giorni di calendario dalla data della presentazione di una domanda ricevibile ai sensi dell’articolo 19.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Detto termine può essere prorogato fino a un massimo di 45 giorni di calendario in singoli casi, segnatamente quando si rende necessario un ulteriore esame della domanda.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 bis.  </span>\n<div class=\"norm inline-element\">La decisione sulla domanda è presa senza indugio in singoli casi d'urgenza giustificati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Salvo in caso di ritiro della domanda, è presa la decisione di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un visto uniforme a norma dell’articolo 24;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un visto con validità territoriale limitata a norma dell’articolo 25;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un visto di transito aeroportuale a norma dell'articolo 26; o</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiutare un visto in conformità dell'articolo 32.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5 —————</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<p class=\"norm\">L’impossibilità fisica di rilevare le impronte digitali a norma dell’articolo 13, paragrafo 7, lettera b), non influisce sul rilascio o sul rifiuto del visto.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Rilascio di un visto uniforme", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il periodo di validità del visto e la durata del soggiorno autorizzato sono basati sull’esame effettuato a norma dell’articolo 21.</div>\n</div>"], [null, "<p class=\"norm\">Un visto può essere rilasciato per uno, due o molteplici ingressi. Il periodo di validità non è superiore a cinque anni.</p>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">Fermo restando l'articolo 12, lettera a), il periodo di validità del visto per ingresso singolo comprende una «franchigia» di 15 giorni di calendario.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Gli Stati membri possono decidere di non concedere tale franchigia per motivi di ordine pubblico o in ragione delle relazioni internazionali di uno degli Stati membri.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A condizione che il richiedente soddisfi le condizioni d'ingresso di cui all'articolo 6, paragrafo 1, lettera a) e lettere da c) a e), del regolamento (UE) 2016/399, i visti per ingressi multipli con un lungo periodo di validità sono rilasciati per i seguenti periodi di validità, a meno che la validità del visto superi quella del documento di viaggio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un anno, purché il richiedente abbia ottenuto e usato legittimamente tre visti nei due anni precedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">due anni, purché il richiedente abbia ottenuto e usato legittimamente un precedente visto per ingressi multipli della validità di un anno nei due anni precedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cinque anni, purché il richiedente abbia ottenuto e usato legittimamente un precedente visto per ingressi multipli della validità di due anni nei tre anni precedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per il rilascio dei visti per ingressi multipli non si tiene conto dei visti di transito aeroportuale e dei visti con validità territoriale limitata rilasciati in conformità dell'articolo 25, paragrafo 1.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 bis.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, il periodo di validità del visto rilasciato può essere ridotto in singoli casi qualora vi sia un ragionevole dubbio sul fatto che le condizioni di ingresso saranno rispettate per l'intero periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 ter.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, i consolati, nell'ambito della cooperazione locale Schengen, valutano se le norme sul rilascio dei visti per ingressi multipli di cui al paragrafo 2 debbano essere adattate per tenere conto delle circostanze locali e dei rischi migratori e per la sicurezza, ai fini dell'adozione di norme più favorevoli o più restrittive in conformità del paragrafo 2 quinquies.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 quater.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, può essere rilasciato un visto per ingressi multipli valido fino a cinque anni ai richiedenti che ne dimostrano la necessità o giustificano l'intenzione di viaggiare frequentemente o con regolarità, purché dimostrino la propria integrità e affidabilità, in particolare l'uso legittimo di precedenti visti, la situazione economica nel paese di origine e l'effettiva intenzione di lasciare il territorio degli Stati membri prima della scadenza del visto che hanno richiesto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 quinquies.  </span>\n<div class=\"norm inline-element\">Ove necessario, sulla base della valutazione di cui al paragrafo 2 ter del presente articolo, la Commissione adotta, mediante atti di esecuzione, norme sulle condizioni per il rilascio dei visti per ingressi multipli di cui al paragrafo 2 del presente articolo, da applicare in ciascuna giurisdizione per tenere conto delle circostanze locali, dei rischi migratori e per la sicurezza e delle relazioni generali dell'Unione con il paese terzo in questione. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 52, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I dati di cui all’articolo 10, paragrafo 1, del regolamento VIS sono inseriti nel VIS una volta presa la decisione sul rilascio del visto.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Rilascio di un visto con validità territoriale limitata", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I visti con validità territoriale limitata sono rilasciati eccezionalmente nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando, per motivi umanitari o di interesse nazionale o in virtù di obblighi internazionali, lo Stato membro interessato ritiene necessario:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">derogare al principio dell’adempimento delle condizioni di ingresso di cui all’articolo 5, paragrafo 1, lettere a), c), d) ed e), del codice frontiere Schengen;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un visto nonostante l’opposizione al rilascio di un visto uniforme manifestata dallo Stato membro consultato a norma dell’articolo 22; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un visto per motivi di urgenza benché non abbia avuto luogo la consultazione preliminare a norma dell’articolo 22;</p>\n</div>\n</div>\n<p class=\"list\">ovvero</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando, per motivi ritenuti giustificati dal consolato, è rilasciato un nuovo visto per un soggiorno durante lo stesso periodo di 180 giorni a un richiedente che, al di là di questo periodo di 180 giorni, ha già utilizzato un visto uniforme o un visto con validità territoriale limitata per un soggiorno di 90 giorni;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Un visto con validità territoriale limitata è valido per il territorio dello Stato membro di rilascio. In via eccezionale può essere valido per il territorio di più Stati membri, fatto salvo il consenso di ciascuno degli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se il richiedente possiede un documento di viaggio non riconosciuto da uno o più Stati membri, ma non tutti, è rilasciato un visto valido per il territorio degli Stati membri che riconoscono il documento di viaggio. Nel caso in cui lo Stato membro di rilascio non riconosca il documento di viaggio del richiedente, il visto rilasciato è valido solo per quello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il visto con validità territoriale limitata è stato rilasciato nei casi di cui al paragrafo 1, lettera a), le autorità centrali dello Stato membro di rilascio procedono, senza indugio e secondo la procedura di cui all’articolo 16, paragrafo 3, del regolamento VIS, alla trasmissione delle informazioni rilevanti alle autorità centrali degli altri Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I dati di cui all’articolo 10, paragrafo 1, del regolamento VIS sono inseriti nel VIS una volta presa la decisione sul rilascio del visto.</div>\n</div>"]]}, "25a": {"label": "Articolo 25 bis", "heading": "Cooperazione in materia di riammissione", "anchor": "art_25a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In funzione del livello di cooperazione di un paese terzo con gli Stati membri in materia di riammissione dei migranti irregolari valutato sulla base di dati pertinenti e obiettivi, l'articolo 14, paragrafo 6, l'articolo 16, paragrafo 1, e paragrafo 5, lettera b), l'articolo 23, paragrafo 1, e l'articolo 24, paragrafi 2 e 2 quater, non si applicano ai richiedenti o alle categorie di richiedenti che sono cittadini di un paese terzo che si ritiene non cooperi a sufficienza in conformità del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione valuta regolarmente, con cadenza almeno annuale, la cooperazione dei paesi terzi in materia di riammissione, tenendo conto, in particolare, dei seguenti indicatori:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di decisioni di rimpatrio emesse nei confronti di persone provenienti dal paese terzo in questione il cui soggiorno nel territorio degli Stati membri è irregolare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di rimpatri forzati effettivi di persone destinatarie di decisioni di rimpatrio in rapporto al numero di decisioni di rimpatrio emesse nei confronti di cittadini del paese terzo in questione, compreso, se del caso, sulla base di accordi di riammissione dell'Unione o bilaterali, il numero di cittadini di paesi terzi che hanno transitato sul territorio del paese terzo in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di riammissione per Stato membro accettate dal paese terzo in rapporto al numero di tali richieste presentate a tale paese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il grado di cooperazione pratica in materia di rimpatrio nelle diverse fasi della procedura di rimpatrio, quali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'assistenza fornita nell'identificazione di persone che soggiornano illegalmente nel territorio degli Stati membri e nel tempestivo rilascio di documenti di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'accettazione del documento di viaggio europeo per il rimpatrio dei cittadini di paesi terzi il cui soggiorno è irregolare o del lasciapassare europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'accettazione della riammissione di persone che per legge devono essere rimpatriate nel loro paese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'accettazione di voli e operazioni di rimpatrio.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tale valutazione è basata sull'uso di dati affidabili forniti da Stati membri, nonché da istituzioni, organi e organismi dell'Unione. La Commissione riferisce periodicamente, con cadenza almeno annuale, al Consiglio in merito a tale valutazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può notificare alla Commissione di incontrare problemi pratici sostanziali e persistenti nella cooperazione con un paese terzo in materia di riammissione di migranti in situazione irregolare, sulla base degli indicatori elencati al paragrafo 2. La Commissione informa immediatamente il Parlamento europeo e il Consiglio di tale notifica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione esamina entro un mese le eventuali notifiche di cui al paragrafo 3. La Commissione informa il Parlamento europeo e il Consiglio dei risultati di tale esame.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora, in base all'analisi di cui ai paragrafi 2 e 4 e tenuto conto delle misure adottate dalla Commissione per migliorare il livello di cooperazione del paese terzo in questione in materia di riammissione e le relazioni generali dell'Unione con tale paese terzo, anche in materia di migrazione, la Commissione ritenga che un paese non cooperi a sufficienza e che pertanto occorra intervenire, o qualora, entro dodici mesi, la maggioranza semplice di Stati membri abbia effettuato una notifica alla Commissione a norma del paragrafo 3, la Commissione, continuando nel contempo ad adoperarsi per migliorare la cooperazione con il paese terzo interessato, presenta al Consiglio una proposta ai fini dell'adozione di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una decisione di esecuzione che sospenda temporaneamente l'applicazione di uno o più dei seguenti articoli, l'articolo 14, paragrafo 6, l'articolo 16, paragrafo 5, lettera b), l'articolo 23, paragrafo 1, o l'articolo 24, paragrafi 2 e 2 quater, a tutti i cittadini del paese terzo in questione o ad alcune categorie di tali cittadini;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una decisione di esecuzione che applichi, in maniera graduale, uno dei diritti per i visti di cui all'articolo 16, paragrafo 2 bis, a tutti i cittadini del paese terzo in questione o ad alcune categorie di tali cittadini, laddove, in seguito a una valutazione della Commissione, le misure applicate conformemente alla decisione di esecuzione di cui alla lettera a) del presente paragrafo siano ritenute inefficaci.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione valuta continuamente e riferisce, sulla base degli indicatori di cui al paragrafo 2, se possano essere constatati miglioramenti sostanziali e duraturi nella cooperazione con il paese terzo interessato in materia di riammissione dei migranti irregolari e, tenendo conto anche delle relazioni generali dell'Unione con detto paese terzo, può presentare al Consiglio una proposta intesa ad abrogare o modificare le decisioni di esecuzione di cui al paragrafo 5.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Entro sei mesi dall'entrata in vigore delle decisioni di esecuzione di cui al paragrafo 5, la Commissione riferisce al Parlamento europeo e al Consiglio in merito ai progressi conseguiti nella cooperazione del paese terzo in questione in materia di riammissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora, sulla base dell'analisi di cui al paragrafo 2 e tenuto conto delle relazioni generali dell'Unione con il paese terzo in questione, segnatamente nella cooperazione in materia di riammissione, ritenga che il paese terzo interessato cooperi a sufficienza, la Commissione può presentare al Consiglio una proposta ai fini dell'adozione di una decisione di esecuzione concernente i richiedenti o le categorie di richiedenti cittadini del paese terzo in questione e che chiedono un visto nel territorio di detto paese terzo e recante una o più delle seguenti misure:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la riduzione a 60 EUR dei diritti per i visti di cui all'articolo 16, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la riduzione a 10 giorni del termine entro il quale vanno prese le decisioni su una domanda di cui all'articolo 23, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'allungamento del periodo di validità dei visti per ingressi multipli di cui all'articolo 24, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tale decisione di esecuzione si applica per massimo un anno. Essa può essere rinnovata.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Rilascio di un visto di transito aeroportuale", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il visto di transito aeroportuale è valido per il transito nelle zone internazionali di transito degli aeroporti situati sul territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fermo restando l’articolo 12, lettera a), il periodo di validità del visto comprende una «franchigia» supplementare di quindici giorni.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono decidere di non concedere tale franchigia per motivi di ordine pubblico o in ragione delle relazioni internazionali di uno degli Stati membri.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 12, lettera a), i visti di transito aeroportuale multipli possono essere rilasciati con un periodo di validità massima di sei mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’adozione della decisione sul rilascio di visti di transito aeroportuale multipli sono rilevanti, in particolare, i seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la necessità del richiedente di transitare frequentemente e/o regolarmente; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’integrità e l’affidabilità del richiedente, in particolare la correttezza nell’uso di precedenti visti uniformi, visti con validità territoriale limitata o visti di transito aeroportuale, la sua situazione economica nel suo paese d’origine e l’effettiva intenzione di proseguire il viaggio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se il richiedente deve essere in possesso di un visto di transito aeroportuale a norma dell’articolo 3, paragrafo 2, il visto di transito aeroportuale è valido solo per il transito nelle zone internazionali degli aeroporti situati sul territorio dello Stato membro o degli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I dati di cui all’articolo 10, paragrafo 1, del regolamento VIS sono inseriti nel VIS una volta presa la decisione sul rilascio del visto.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Modalità di compilazione del visto adesivo", "anchor": "art_27", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, le regole dettagliate di compilazione del visto adesivo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 52, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono aggiungere menzioni nazionali nella zona «annotazioni» del visto adesivo. Tali menzioni non duplicano le menzioni obbligatorie stabilite secondo la procedura di cui al paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Tutte le diciture sul visto adesivo sono stampate e i visti adesivi stampati non possono recare correzioni o cancellature manuali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il visto adesivo per ingresso singolo può essere compilato manualmente solo in caso di forza maggiore per problemi di natura tecnica. Il visto adesivo compilato manualmente non può recare correzioni o cancellature.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di compilazione manuale di un visto adesivo a norma del paragrafo 4 del presente articolo, questa informazione è inserita nel VIS conformemente all’articolo 10, paragrafo 1, lettera k), del regolamento VIS.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Annullamento di un visto adesivo già compilato", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se si individua un errore nel visto adesivo prima di apporlo sul documento di viaggio, il visto adesivo è annullato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se si individua un errore dopo aver apposto il visto adesivo sul documento di viaggio, il visto adesivo è annullato barrandolo con una croce decussata in inchiostro indelebile e si procede all’apposizione di un nuovo visto su un’altra pagina.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se si individua un errore dopo che i dati rilevanti sono stati inseriti nel VIS conformemente all’articolo 10, paragrafo 1, del regolamento VIS, l’errore è rettificato a norma dell’articolo 24, paragrafo 1, dello stesso regolamento.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Apposizione di un visto adesivo", "anchor": "art_29", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il visto adesivo è apposto sul documento di viaggio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, le norme dettagliate di apposizione del visto adesivo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 52, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro di rilascio non riconosce il documento di viaggio del richiedente, è utilizzato il foglio separato per l’apposizione del visto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di apposizione del visto adesivo sul foglio separato per l’apposizione del visto, questa informazione è inserita nel VIS conformemente all’articolo 10, paragrafo 1, lettera j), del regolamento VIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I visti individuali rilasciati alle persone figuranti sul documento di viaggio del richiedente sono apposti su tale documento di viaggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se lo Stato membro di rilascio non riconosce il documento di viaggio su cui figurano tali persone, il visto adesivo individuale è apposto sui fogli separati per l’apposizione di un visto.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Diritti derivati dal rilascio di un visto", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">Il possesso di un visto uniforme o di un visto con validità territoriale limitata non conferisce un diritto automatico di ingresso.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Informazione delle autorità centrali degli altri Stati membri", "anchor": "art_31", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può chiedere che le proprie autorità centrali siano informate sui visti rilasciati da altri Stati membri ai cittadini di determinati paesi terzi o a specifiche categorie di tali cittadini, salvo in caso di visti di transito aeroportuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione l'introduzione o il ritiro della richiesta relativa a tale informazione almeno 25 giorni di calendario prima che detta misura diventi applicabile. Tale informazione è comunicata anche nell'ambito della cooperazione locale Schengen all'interno della giurisdizione interessata.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione informa gli Stati membri di tali notifiche.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "32": {"label": "Articolo 32", "heading": "Rifiuto di un visto", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ferme restando le disposizioni di cui all’articolo 25, paragrafo 1, il visto è rifiutato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando il richiedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un documento di viaggio falso, contraffatto o alterato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non fornisce la giustificazione riguardo allo scopo e alle condizioni del soggiorno previsto;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non fornisce la giustificazione riguardo allo scopo e alle condizioni del transito aeroportuale previsto;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non dimostra di disporre di mezzi di sussistenza sufficienti, sia per la durata prevista del soggiorno sia per il ritorno nel paese di origine o di residenza oppure per il transito verso un paese terzo nel quale la sua ammissione è garantita, ovvero non è in grado di ottenere legalmente detti mezzi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">abbia già soggiornato per 90 giorni nell’arco del periodo di 180 giorni in corso, sul territorio degli Stati membri in virtù di un visto uniforme o di un visto con validità territoriale limitata;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è segnalato nel SIS al fine della non ammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia considerato una minaccia per l’ordine pubblico, la sicurezza interna o la salute pubblica, quale definita all’articolo 2, paragrafo 19, del codice frontiere Schengen, o per le relazioni internazionali di uno degli Stati membri e, in particolare, sia segnalato nelle banche dati nazionali degli Stati membri ai fini della non ammissione per gli stessi motivi; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non dimostra di possedere un’adeguata e valida assicurazione sanitaria di viaggio, ove applicabile;</p>\n</div>\n</div>\n<p class=\"list\">oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora vi siano ragionevoli dubbi sull’autenticità dei documenti giustificativi presentati dal richiedente o sulla veridicità del loro contenuto, sull’affidabilità delle dichiarazioni fatte dal richiedente o sulla sua intenzione di lasciare il territorio degli Stati membri prima della scadenza del visto richiesto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione di rifiuto e i motivi su cui si basa sono notificati al richiedente mediante il modulo uniforme di cui all'allegato VI nella lingua dello Stato membro che ha adottato la decisione definitiva in merito alla domanda e in un'altra lingua ufficiale delle istituzioni dell'Unione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I richiedenti cui sia stato rifiutato il visto hanno il diritto di presentare ricorso. I ricorsi sono proposti nei confronti dello Stato membro che ha adottato la decisione definitiva in merito alla domanda e disciplinati conformemente alla legislazione nazionale di tale Stato membro. Gli Stati membri forniscono ai richiedenti informazioni sulla procedura cui attenersi in caso di ricorso, come precisato nell’allegato VI.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le informazioni sui visti rifiutati sono inserite nel VIS conformemente all’articolo 12 del regolamento VIS.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Proroga", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il periodo di validità e/o la durata del soggiorno, in relazione a un visto rilasciato sono prorogati qualora l’autorità competente di uno Stato membro ritenga che un titolare del visto abbia dimostrato l’esistenza di motivi di forza maggiore o di ragioni umanitarie che gli impediscono di lasciare il territorio degli Stati membri prima della scadenza del periodo di validità del visto o della durata del soggiorno da esso autorizzato. Tale proroga è concessa a titolo gratuito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il periodo di validità e/o la durata del soggiorno in relazione a un visto rilasciato possono essere prorogati qualora il titolare del visto dimostri l’esistenza di ragioni personali serie che giustifichino la proroga del periodo di validità o della durata del soggiorno. Tale proroga dà luogo alla riscossione di un diritto pari a 30 EUR.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Salvo diversa decisione dell’autorità che dispone la proroga del visto, la validità territoriale del visto prorogato rimane uguale a quella del visto originario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’autorità competente a prorogare il visto è quella dello Stato membro sul cui territorio si trova il cittadino del paese terzo al momento della richiesta della proroga.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione le autorità competenti per la proroga dei visti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La proroga del visto assume la forma di un visto adesivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le informazioni sul visto prorogato sono inserite nel VIS conformemente all’articolo 14 del regolamento VIS.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Annullamento e revoca", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un visto è annullato qualora risulti che le condizioni di rilascio dello stesso non erano soddisfatte al momento del rilascio, in particolare se vi sono fondati motivi per ritenere che il visto sia stato ottenuto in modo fraudolento. Un visto è annullato, in linea di principio, dalle autorità competenti dello Stato membro di rilascio. Un visto può essere annullato dalle autorità competenti di un altro Stato membro, nel qual caso le autorità dello Stato membro di rilascio sono informate dell’annullamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Un visto è revocato qualora risulti che le condizioni di rilascio dello stesso non sono più soddisfatte. Un visto è revocato, in linea di principio, dalle autorità competenti dello Stato membro di rilascio. Un visto può essere revocato dalle autorità competenti di un altro Stato membro, nel qual caso le autorità dello Stato membro di rilascio sono informate della revoca.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Un visto può essere revocato su richiesta del suo titolare. Le autorità competenti dello Stato membro di rilascio del visto sono informate di tale revoca.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La mancata presentazione da parte del titolare, alla frontiera, di uno o più dei documenti giustificativi di cui all’articolo 14, paragrafo 3, non dà automaticamente origine a una decisione di annullamento o di revoca del visto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di annullamento o revoca, è apposto sul visto il timbro «ANNULLATO» o «REVOCATO» e l’elemento otticamente variabile della vignetta visto, l’elemento di sicurezza «effetto immagine latente» e la scritta «visto» sono annullati cancellandoli.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La decisione di annullamento o di revoca di un visto e i motivi su cui si basa sono notificati al richiedente mediante il modulo uniforme di cui all’allegato VI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Un titolare il cui visto sia stato annullato o revocato ha il diritto di presentare ricorso, a meno che il visto sia stato revocato su sua richiesta conformemente al paragrafo 3. I ricorsi sono proposti nei confronti dello Stato membro che ha adottato la decisione in merito all’annullamento o alla revoca e disciplinati conformemente alla legislazione nazionale di tale Stato membro. Gli Stati membri forniscono ai richiedenti informazioni sulla procedura cui attenersi in caso di ricorso, come precisato nell’allegato VI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Le informazioni su un visto annullato o revocato sono inserite nel VIS conformemente all’articolo 13 del regolamento VIS.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Visti chiesti alle frontiere esterne", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In casi eccezionali, i visti possono essere rilasciati ai valichi di frontiera se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente soddisfa le condizioni di cui all’articolo 5, paragrafo 1, lettere a, c), d) ed e), del codice frontiere Schengen;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente non ha avuto modo di chiedere un visto anticipatamente e presenta, su richiesta, documenti giustificativi comprovanti l’esistenza di motivi imprevedibili e imperativi d’ingresso, e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ritorno del richiedente nel paese di origine o di residenza ovvero il suo transito attraverso Stati diversi dagli Stati membri che applicano integralmente l’acquis di Schengen è considerato sicuro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando un visto è chiesto alle frontiere esterne si può derogare all’obbligo per il richiedente di disporre di un’assicurazione sanitaria di viaggio se tale assicurazione non è disponibile al valico di frontiera o per motivi umanitari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Un visto rilasciato alle frontiere esterne è un visto uniforme che autorizza il titolare a un soggiorno di una durata massima di quindici giorni, a seconda dello scopo e delle condizioni del soggiorno previsto. In caso di transito, la durata del soggiorno autorizzato corrisponde al tempo necessario per il transito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non siano soddisfatte le condizioni di cui all’articolo 5, paragrafo 1, lettere a), c), d) ed e), del codice frontiere Schengen, le autorità responsabili del rilascio del visto alla frontiera possono emettere, a norma dell’articolo 25, paragrafo 1, lettera a), del presente regolamento, un visto con validità territoriale limitata al solo Stato membro di rilascio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ai cittadini di paesi terzi che rientrano nella categoria di persone per le quali è richiesta la consultazione preliminare ai sensi dell’articolo 22 non viene, in linea di principio, rilasciato un visto alla frontiera esterna.</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, in casi eccezionali, per queste persone può essere emesso alla frontiera un visto con validità territoriale limitata allo Stato membro di rilascio, ai sensi dell’articolo 25, paragrafo 1, lettera a).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Oltre ai motivi di rifiuto del visto previsti all’articolo 32, paragrafo 1, il visto è rifiutato al valico di frontiera se non sono soddisfatte le condizioni di cui al paragrafo 1, lettera b), del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Si applicano le disposizioni sui motivi e sulla notifica dei rifiuti e sul diritto di ricorso di cui all’articolo 32, paragrafo 3, e all’allegato VI.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Visti rilasciati alla frontiera esterna a marittimi in transito", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A un marittimo che deve essere in possesso di un visto per l’attraversamento delle frontiere esterne degli Stati membri può essere rilasciato un visto ai fini del transito alla frontiera se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soddisfa le condizioni di cui all’articolo 35, paragrafo 1; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attraversa la frontiera in questione per l’imbarco, il reimbarco o lo sbarco da una nave a bordo della quale lavorerà o ha lavorato in qualità di marittimo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 bis.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, istruzioni operative per il rilascio alla frontiera di visti ai marittimi. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 52, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica fatte salve le disposizioni di cui all’articolo 35, paragrafi 3, 4 e 5.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Organizzazione del servizio visti", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sono competenti per l’organizzazione del servizio visti dei loro consolati.</div>\n</div>"], [null, "<p class=\"norm\">Per evitare qualsiasi riduzione del livello di vigilanza e per proteggere il personale da pressioni a livello locale, sono istituiti, ove opportuno, sistemi di rotazione per il personale che tratta direttamente con i richiedenti. È prestata particolare attenzione a introdurre chiare strutture di lavoro e precise assegnazioni/divisioni delle responsabilità in relazione all’adozione delle decisioni finali relative alle domande. L’accesso alla consultazione del VIS o del SIS e ad altre informazioni riservate è ristretto a un numero limitato di membri del personale debitamente autorizzati. Sono adottate misure appropriate per impedire l’accesso non autorizzato a tali banche dati.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La conservazione e l'uso dei visti adesivi sono soggetti ad adeguate misure di sicurezza per evitare frodi o perdite. Ogni consolato tiene una contabilità della sua scorta di visti adesivi e registra come è stato utilizzato ciascun visto adesivo. Eventuali perdite significative di visti adesivi in bianco sono comunicate alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I consolati o le autorità centrali tengono archivi cartacei o elettronici delle domande. Ogni fascicolo individuale contiene informazioni utili per ricostruire, se necessario, il contesto della decisione presa sulla domanda.</div>\n</div>"], [null, "<p class=\"norm\">I fascicoli individuali sono conservati per almeno un anno a decorrere dalla data della decisione sulla domanda di cui all'articolo 23, paragrafo 1, o, in caso di ricorso, fino alla conclusione della procedura di ricorso, se più lunga. Se applicabile, i fascicoli individuali elettronici sono conservati per il periodo di validità del visto rilasciato.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "38": {"label": "Articolo 38", "heading": "Risorse per l'esame delle domande e il controllo delle procedure di rilascio del visto", "anchor": "art_38", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri predispongono nei consolati personale adeguato e in numero sufficiente per svolgere le mansioni di esame delle domande, in modo tale da garantire una qualità ragionevole e armonizzata del servizio al pubblico.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché l'intera procedura di rilascio del visto nei consolati, compresi la presentazione e il trattamento delle domande, la stampa dei visti adesivi e la cooperazione pratica con i fornitori esterni di servizi, sia controllata da personale espatriato per garantire l'integrità di tutte le fasi della procedura.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I locali rispondono a determinati requisiti di adeguatezza funzionale e prevedono appropriate misure di sicurezza.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le autorità centrali degli Stati membri provvedono a una formazione adeguata sia del personale espatriato che di quello locale e a esse spetta fornire a tale personale informazioni complete, precise e aggiornate sul diritto dell'Unione e nazionale pertinente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 bis.  </span>\n<div class=\"norm inline-element\">Quando le domande sono esaminate e decise dalle autorità centrali di cui all'articolo 4, paragrafo 1 bis, gli Stati membri forniscono una formazione specifica per assicurare che il personale di tali autorità centrali sia in possesso di sufficienti e aggiornate conoscenze specifiche per paese della situazione socioeconomica locale e di informazioni complete, precise e aggiornate sul diritto dell'Unione e nazionale pertinente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 ter.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono inoltre affinché i consolati dispongano di personale sufficiente e adeguatamente formato per assistere le autorità centrali nell'esame e nelle decisioni sulle domande, in particolare partecipando alle riunioni di cooperazione locale Schengen, scambiando informazioni con altri consolati e autorità locali, raccogliendo a livello locale informazioni utili sui rischi migratori e sulle pratiche fraudolente e procedendo a colloqui ed esami aggiuntivi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le autorità centrali degli Stati membri assicurano un controllo frequente e adeguato delle modalità di esame delle domande e adottano provvedimenti correttivi qualora siano rilevate violazioni delle disposizioni del presente regolamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri provvedono a istituire una procedura che consenta ai richiedenti di presentare reclami per quanto concerne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la condotta del personale presso i consolati e, se del caso, dei fornitori esterni di servizi; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la procedura di domanda.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I consolati o le autorità centrali tengono un registro dei reclami e del seguito loro riservato.</p>"], [null, "<p class=\"norm\">Gli Stati membri rendono disponibili al pubblico le informazioni sulla procedura di cui al presente paragrafo.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "39": {"label": "Articolo 39", "heading": "Condotta del personale", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I consolati degli Stati membri garantiscono che i richiedenti vengano accolti cortesemente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il personale consolare e delle autorità centrali, nell'esercizio delle sue funzioni, rispetta pienamente la dignità umana. Tutti i provvedimenti adottati sono proporzionati agli obiettivi da essi perseguiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nello svolgimento dei suoi compiti il personale consolare e delle autorità centrali non pone in atto discriminazioni nei confronti delle persone per motivi di sesso, razza od origine etnica, religione o convinzioni personali, disabilità, età od orientamento sessuale.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Organizzazione e cooperazione consolare", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro è responsabile dell'organizzazione delle procedure connesse alle domande.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dotano del materiale necessario per il rilevamento degli identificatori biometrici i loro consolati e le autorità competenti per il rilascio dei visti alla frontiera nonché gli uffici dei loro consoli onorari, qualora ricorrano a essi, per il rilevamento degli identificatori biometrici conformemente all'articolo 42;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cooperano con uno o più Stati membri nell'ambito di accordi di rappresentanza o altre forme di cooperazione consolare.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può anche cooperare con un fornitore esterno di servizi in conformità dell'articolo 43.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri notificano alla Commissione la loro organizzazione e cooperazione consolare in ciascuna rappresentanza consolare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di cessazione della cooperazione con altri Stati membri, gli Stati membri si adoperano per assicurare la continuità del servizio completo.</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Cooperazione con fornitori esterni di servizi", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri si adoperano per cooperare con un fornitore esterno di servizi assieme a uno o più Stati membri, fatte salve le norme in materia di appalti pubblici e concorrenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La cooperazione con un fornitore esterno di servizi si basa su uno strumento giuridico conforme ai requisiti riportati nell’allegato X.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’esame delle domande, i colloqui (se del caso), la decisione sulle domande e la stampa e l’apposizione dei visti adesivi competono esclusivamente al consolato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I fornitori esterni di servizi non hanno in alcun caso accesso al VIS. L'accesso al VIS è riservato esclusivamente al personale debitamente autorizzato dei consolati o delle autorità centrali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un fornitore esterno di servizi può essere autorizzato a svolgere uno o più dei seguenti compiti:</p>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire informazioni generali sui requisiti per presentare domanda di visto, in conformità dell'articolo 47, paragrafo 1, lettere da a) a c), e sui moduli di domanda;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informare il richiedente dei documenti giustificativi richiesti, sulla scorta di una lista di controllo;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">raccogliere dati e domande (compresi gli identificatori biometrici) e trasmettere la domanda al consolato o alle autorità centrali;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riscuotere i diritti per i visti;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestire, se del caso, gli appuntamenti dei richiedenti presso il consolato o i locali del fornitore esterno di servizi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ritirare i documenti di viaggio, compresa, se del caso, la notifica del rifiuto, presso il consolato o le autorità centrali e restituirli al richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Nel selezionare un fornitore esterno di servizi, lo Stato membro interessato verifica l'affidabilità e la solvibilità dell'organizzazione o dell'impresa e si assicura che non intervengano conflitti di interesse. Tale valutazione comprende, ove opportuno, l'esame delle licenze necessarie, l'iscrizione al registro delle imprese, lo statuto e i contratti bancari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o gli Stati membri interessati provvedono affinché il fornitore esterno di servizi selezionato rispetti le modalità e le condizioni che lo riguardano nello strumento giuridico di cui al paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sono responsabili del rispetto delle norme sulla protezione dei dati personali e garantiscono che il fornitore esterno di servizi sia soggetto alla sorveglianza delle autorità di controllo preposte alla protezione dei dati a norma dell'articolo 51, paragrafo 1, del regolamento (UE) 2016/679 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">10</span>\n).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o gli Stati membri interessati assicurano la formazione del fornitore esterno di servizi corrispondente alla conoscenza necessaria per fornire un servizio adeguato e informazioni sufficienti ai richiedenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro o gli Stati membri interessati sorvegliano strettamente l’esecuzione dello strumento giuridico di cui al paragrafo 2 e verificano in particolare:</p>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni generali sui criteri, sulle condizioni e sulle procedure per presentare domanda di visto, di cui all'articolo 47, paragrafo 1, lettere da a) a c), e il contenuto dei moduli di domanda forniti dal fornitore esterno di servizi ai richiedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le misure di sicurezza tecniche e organizzative necessarie per tutelare i dati personali dalla distruzione accidentale o illecita, dalla perdita accidentale, dall'alterazione, dall'accesso o divulgazione non autorizzati, in particolare quando la cooperazione comporti la trasmissione di pratiche e dati al consolato o alle autorità centrali dello Stato membro o degli Stati membri interessati, e da qualsiasi altra forma illecita di trattamento di dati personali;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la raccolta e trasmissione degli identificatori biometrici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le misure adottate per assicurare l’osservanza delle norme sulla protezione dei dati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">A tal fine, il consolato o i consolati o le autorità centrali dello Stato membro o degli Stati membri interessati effettuano periodicamente, almeno ogni nove mesi, controlli a campione nei locali del fornitore esterno di servizi. Gli Stati membri possono concordare di ripartire gli oneri di questo controllo periodico.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11 bis.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> febbraio di ogni anno gli Stati membri riferiscono alla Commissione in merito alla loro cooperazione con i fornitori esterni di servizi in tutto il mondo e al monitoraggio dei medesimi di cui all'allegato X, punto C).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Nell’eventualità che cessi la cooperazione con qualsiasi fornitore esterno di servizi, gli Stati membri assicurano la continuità del servizio completo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione una copia dello strumento giuridico di cui al paragrafo 2.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Cifratura e trasferimento sicuro di dati", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In caso di cooperazione tra Stati membri, cooperazione con un fornitore esterno di servizi e ricorso a consoli onorari, lo Stato membro o gli Stati membri interessati provvedono alla cifratura totale dei dati trasferiti per via elettronica o fisicamente su un supporto di memorizzazione elettronica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei paesi terzi che vietano la cifratura dei dati da trasmettere per via elettronica, lo Stato membro o gli Stati membri interessati non permettono che i dati siano trasferiti per via elettronica.</div>\n</div>"], [null, "<p class=\"norm\">In tal caso, lo Stato membro o gli Stati membri interessati provvedono al trasferimento fisico dei dati elettronici in forma totalmente cifrata su un supporto di memorizzazione elettronica da parte di un agente consolare di uno Stato membro o, qualora questo tipo di trasferimento richieda il ricorso a misure sproporzionate o irragionevoli, in un altro modo sicuro e protetto, per esempio ricorrendo a operatori consolidati con esperienza nel trasporto di documenti e dati sensibili nel paese terzo in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In tutti i casi il livello di sicurezza del trasferimento è adeguato alla natura sensibile dei dati.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Cooperazione degli Stati membri con intermediari commerciali", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono cooperare con intermediari commerciali per la presentazione delle domande, fatta eccezione per la raccolta di identificatori biometrici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tale cooperazione è basata sulla concessione di un accreditamento da parte delle pertinenti autorità degli Stati membri. L’accreditamento, in particolare, è basato sulla verifica dei seguenti aspetti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">situazione attuale dell’intermediario commerciale: validità della licenza, iscrizione nel registro delle imprese, contratti con le banche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contratti esistenti con partner commerciali stabiliti negli Stati membri che offrono alloggio e altri servizi nell’ambito di un viaggio combinato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contratti con le compagnie di trasporto, che devono comprendere un viaggio di andata nonché un viaggio di ritorno garantito e chiuso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli intermediari commerciali accreditati sono monitorati regolarmente mediante controlli a campione che comprendono colloqui personali o telefonici con i richiedenti, l'accertamento dei viaggi e dei pernottamenti e, per quanto ritenuto necessario, la prova documentale del ritorno in gruppo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nell’ambito della cooperazione locale Schengen ha luogo uno scambio di informazioni sulla prestazione degli intermediari commerciali accreditati sulle irregolarità riscontrate e sul rifiuto di domande presentate da parte degli intermediari commerciali e sulle frodi riscontrate nella documentazione di viaggio e il mancato svolgimento del viaggio programmato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nell’ambito della cooperazione locale Schengen ha luogo lo scambio degli elenchi degli intermediari commerciali accreditati dai consolati o ai quali essi abbiano ritirato l’accreditamento, con l’informazione, in quest’ultimo caso, sulle circostanze che hanno determinato tale ritiro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">Ogni consolato e le autorità centrali assicurano l'informazione dei cittadini sull'elenco degli intermediari commerciali accreditati con cui stabiliscono una cooperazione, se del caso.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "46": {"label": "Articolo 46", "heading": "Compilazione di statistiche", "anchor": "art_46", "frags": [[null, "<p class=\"norm\">Gli Stati membri compilano statistiche annuali sui visti, conformemente alla tabella che figura nell’allegato XII. Queste statistiche sono presentate entro il 1<span class=\"superscript\">o</span> marzo di ogni anno per l’anno civile precedente.</p>"]]}, "47": {"label": "Articolo 47", "heading": "Informazioni al pubblico", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità centrali e i consolati degli Stati membri forniscono al pubblico tutte le informazioni rilevanti in merito alle domande di visto, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri, le condizioni e le procedure per presentare domanda;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri in base ai quali una domanda può essere considerata ricevibile di cui all'articolo 19, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a ter) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che i dati biometrici devono essere raccolti, in linea di principio, ogni 59 mesi a partire dalla data della prima raccolta;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità per ottenere un appuntamento, ove applicabile;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dove poter presentare domanda (al consolato competente o a un fornitore esterno di servizi);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli intermediari commerciali accreditati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che il timbro di cui all’articolo 20 non ha effetti giuridici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i termini per l’esame delle domande di cui all’articolo 23, paragrafi 1, 2 e 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paesi terzi i cui cittadini o specifiche categorie di cittadini sono oggetto di consultazione preliminare o informazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che eventuali decisioni negative relative alle domande devono essere notificate al richiedente, che tali decisioni devono indicare i motivi su cui si basano e che il richiedente la cui domanda è rifiutata ha diritto di proporre ricorso, con le informazioni riguardo alle procedure cui attenersi in caso di ricorso, compresa l’autorità giudiziaria competente, nonché i termini per presentarlo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il semplice possesso di un visto non conferisce automaticamente il diritto di ingresso e che i titolari di un visto sono invitati a dimostrare di soddisfare le condizioni di ingresso alla frontiera esterna, di cui all’articolo 5 del codice frontiere Schengen;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M5\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulla procedura di reclamo di cui all'articolo 38, paragrafo 5.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro rappresentante e lo Stato membro rappresentato informano i cittadini in merito agli accordi di rappresentanza di cui all’articolo 8 prima della loro entrata in vigore.</div>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Cooperazione locale Schengen fra i consolati degli Stati membri", "anchor": "art_48", "frags": [[null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I consolati e le delegazioni dell'Unione cooperano in ciascuna giurisdizione per garantire un'applicazione armonizzata della politica comune dei visti tenendo conto delle circostanze locali.</div>\n</div>"], [null, "<p class=\"norm\">A tale scopo, in conformità dell'articolo 5, paragrafo 3, della decisione 2010/427/UE del Consiglio (\n<span class=\"superscript\">11</span>\n), la Commissione impartisce istruzioni alle delegazioni dell'Unione affinché svolgano i pertinenti compiti di coordinamento previsti dal presente articolo.</p>"], [null, "<p class=\"norm\">Qualora le domande presentate nella giurisdizione interessata siano esaminate e decise dalle autorità centrali di cui all'articolo 4, paragrafo 1 bis, gli Stati membri assicurano il coinvolgimento attivo di tali autorità centrali nella cooperazione locale Schengen. Il personale che contribuisce alla cooperazione locale Schengen riceve un'adeguata formazione ed è opportunamente coinvolto nell'esame delle domande nella giurisdizione interessata.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri e la Commissione cooperano, in particolare, al fine di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compilare un elenco armonizzato dei documenti giustificativi che i richiedenti devono presentare, tenendo conto dell'articolo 14;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare un'applicazione locale dell'articolo 24, paragrafo 2, relativa al rilascio di visti per ingressi multipli;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere a una traduzione comune del modulo di domanda, se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">compilare l'elenco dei documenti di viaggio rilasciati dal paese ospitante e aggiornarlo regolarmente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stilare una scheda informativa comune contenente le informazioni di cui all'articolo 47, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">controllare, se del caso, l'applicazione dell'articolo 25 bis, paragrafi 5 e 6.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell'ambito della cooperazione locale Schengen gli Stati membri si scambiano le seguenti informazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">statistiche trimestrali su visti uniformi, visti con validità territoriale limitata e visti di transito aeroportuale chiesti, rilasciati e rifiutati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni relative alla valutazione dei rischi migratori e per la sicurezza, in particolare concernenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la struttura socioeconomica del paese ospitante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le fonti di informazione a livello locale, comprese quelle sulla sicurezza sociale, l'assicurazione sanitaria, i registri fiscali e la registrazione degli ingressi e delle uscite;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'impiego di documenti falsi, contraffatti o alterati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le rotte dell'immigrazione irregolare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tendenze in materia di condotta fraudolenta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tendenze relative ai rifiuti di visto;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulla cooperazione con i fornitori esterni di servizi e con le compagnie di trasporto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle compagnie di assicurazione che forniscono un'adeguata assicurazione sanitaria di viaggio, inclusa la verifica del tipo di copertura e del possibile importo in eccesso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sono organizzate su base regolare fra gli Stati membri e la Commissione riunioni di cooperazione locale Schengen per trattare specificamente questioni operative relative all’applicazione della politica comune in materia di visti. Queste riunioni sono convocate nella giurisdizione dalla Commissione, se non diversamente convenuto su richiesta della Commissione stessa.</div>\n</div>"], [null, "<p class=\"norm\">Per studiare questioni specifiche nel quadro della cooperazione locale Schengen possono essere organizzate riunioni monotematiche e possono essere costituiti sottogruppi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Relazioni sintetiche delle riunioni di cooperazione locale Schengen sono stilate regolarmente e diffuse a livello locale. La Commissione può delegare la stesura delle relazioni a uno Stato membro. I consolati di ciascuno Stato membro inoltrano le relazioni alle proprie autorità centrali.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Rappresentanti dei consolati degli Stati membri che non applicano l’acquis comunitario in relazione ai visti, o di paesi terzi, possono essere invitati ad hoc a partecipare alle riunioni ai fini dello scambio di informazioni su questioni attinenti ai visti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Entro il 31 dicembre di ogni anno è redatta una relazione annuale all'interno di ciascuna giurisdizione. In base a tali relazioni la Commissione stila una relazione annuale sullo stato della cooperazione locale Schengen da presentare al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "49": {"label": "Articolo 49", "heading": "Regimi relativi ai Giochi olimpici e paraolimpici", "anchor": "art_49", "frags": [[null, "<p class=\"norm\">Gli Stati membri che ospitano i Giochi olimpici e paraolimpici applicano le specifiche procedure e condizioni per la facilitazione del rilascio dei visti come indicato all’allegato XI.</p>"]]}, "51": {"label": "Articolo 51", "heading": "Istruzioni relative all'applicazione pratica del presente regolamento", "anchor": "art_51", "frags": [[null, "<p class=\"norm\">La Commissione adotta, mediante atti di esecuzione, le istruzioni operative relative all'applicazione pratica delle disposizioni del presente regolamento. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all'articolo 52, paragrafo 2.</p>"]]}, "51a": {"label": "Articolo 51 bis", "heading": "Esercizio della delega", "anchor": "art_51a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 16, paragrafo 9, è conferito alla Commissione per un periodo di cinque anni a decorrere dal 1<span class=\"superscript\">o</span> agosto 2019. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di cinque anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all'articolo 16, paragrafo 9, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell'adozione dell'atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell'accordo interistituzionale «Legiferare meglio» del 13 aprile 2016 (\n<span class=\"superscript\">12</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L'atto delegato adottato ai sensi dell'articolo 16, paragrafo 9, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Procedura di comitato", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato («il comitato visti»). Esso è un comitato ai sensi del regolamento (UE) n. 182/2011 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">13</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l'articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"]]}, "53": {"label": "Articolo 53", "heading": "Comunicazioni", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli accordi di rappresentanza di cui all’articolo 8;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paesi terzi ai cui cittadini i singoli Stati membri richiedono di essere in possesso di un visto di transito aeroportuale per il transito nelle zone internazionali di transito degli aeroporti situati sul loro territorio, di cui all’articolo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il modulo nazionale per la dichiarazione di garanzia e/o di alloggio privato, di cui all’articolo 14, paragrafo 4, se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco dei paesi terzi per i quali è richiesta la consultazione preliminare di cui all’articolo 22, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco dei paesi terzi per i quali sono richieste le informazioni di cui all’articolo 31, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le menzioni nazionali aggiuntive nella zona «annotazioni» del visto adesivo come previsto all’articolo 27, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le autorità competenti per la proroga dei visti, di cui all’articolo 33, paragrafo 5;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le forme di cooperazione di cui all’articolo 40;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le statistiche compilate ai sensi dell’articolo 46 e l’allegato XII.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione mette a disposizione degli Stati membri e del pubblico, tramite pubblicazione elettronica costantemente aggiornata, le informazioni comunicate a norma del paragrafo 1.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Modifiche del regolamento (CE) n. 767/2008", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 767/2008 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 4, il punto 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“visto uniforme” come definito all’articolo 2, paragrafo 3, del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio, del 13 luglio 2009, che istituisce un codice comunitario dei visti (codice dei visti) (\n<span class=\"superscript\">*1</span>\n);</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera b) è soppressa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“visto di transito aeroportuale” come definito all’articolo 2, paragrafo 5, del regolamento (CE) n. 810/2009;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera d) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“visto con validità territoriale limitata”, come definito all’articolo 2, paragrafo 4, del regolamento (CE) n. 810/2009;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera e) è soppressa;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 8, paragrafo 1, i termini «Non appena ricevuta la domanda» sono sostituiti dai seguenti:</p>\n<p class=\"list\">\n                              «Quando la domanda è ricevibile a norma dell’articolo 19 del regolamento (CE) n. 810/2009»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 9 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il titolo è sostituito dal seguente:</p>\n<p class=\"stitle-article-quoted\">«Dati da inserire alla presentazione della domanda»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 4 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome, cognome alla nascita (precedente/i cognome/i), nome/i; data di nascita, luogo di nascita, paese di nascita, sesso;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera e) è soppressa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera g) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Stato/i membro/i di destinazione e durata del soggiorno o del transito previsti;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera h) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">scopo/i principale/i del viaggio;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera i) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di arrivo nell’area Schengen e data di partenza dall’area Schengen previste;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera j) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Stato membro del primo ingresso;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera k) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo del domicilio del richiedente;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla lettera l), i termini «della scuola» sono sostituiti dai termini: «dell’istituto di insegnamento»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ix) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla lettera m), i termini «del padre e della madre» sono sostituiti dai termini «del titolare della potestà genitoriale o del tutore legale»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 10, paragrafo 1, è aggiunta la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, informazioni indicanti che il visto adesivo è stato compilato a mano.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 11, l’elemento di frase introduttivo è sostituito dal seguente:</p>\n<p class=\"norm\">\n                                    «Qualora l’autorità competente per i visti per conto di un altro Stato membro interrompa l’esame della domanda, aggiunge al fascicolo i seguenti dati:»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 12 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo stato della procedura, con l’indicazione che il visto è stato rifiutato e se tale autorità lo abbia rifiutato a nome di un altro Stato membro;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel fascicolo devono altresì figurare uno o più dei seguenti motivi che giustificano il rifiuto del visto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un documento di viaggio falso, contraffatto o alterato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non fornisce la giustificazione riguardo allo scopo e alle condizioni del soggiorno previsto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non dimostra di disporre di mezzi di sussistenza sufficienti, sia per la durata prevista del soggiorno sia per il ritorno nel paese di origine o di residenza oppure per il transito verso un paese terzo nel quale la sua ammissione è garantita, ovvero non è in grado di ottenere legalmente detti mezzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha già soggiornato per tre mesi, nell’arco del periodo di sei mesi in corso, sul territorio degli Stati membri in virtù di un visto uniforme o di un visto con validità territoriale limitata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è segnalato nel SIS al fine della non ammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è considerato una minaccia per l’ordine pubblico, la sicurezza interna, la salute pubblica, quali definiti all’articolo 2, punto 19 del codice frontiere Schengen, o le relazioni internazionali di uno degli Stati membri e, in particolare, è segnalato per gli stessi motivi nelle banche dati nazionali degli Stati membri ai fini della non ammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non dimostra di possedere un’adeguata e valida assicurazione sanitaria di viaggio, ove applicabile;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni fornite per giustificare lo scopo e le condizioni del soggiorno previsto non sono attendibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’intenzione del richiedente di lasciare il territorio degli Stati membri prima della scadenza del visto richiesto non può essere stabilita con certezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non è fornita prova sufficiente che al richiedente non è stato possibile chiedere il visto anticipatamente, per giustificare la presentazione della domanda di visto alla frontiera;»</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 13 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 13</p>\n<p class=\"stitle-article-quoted\">Dati da aggiungere in caso di annullamento o di revoca di un visto</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora sia adottata una decisione di annullamento o di revoca di un visto, l’autorità competente per i visti che ha adottato tale decisione aggiunge al fascicolo i seguenti dati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo stato della procedura, con l’indicazione che il visto è stato annullato o revocato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">autorità che ha annullato o revocato il visto e relativa sede;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo e data della decisione;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel fascicolo relativo alla domanda devono altresì figurare uno o più dei seguenti motivi che giustificano l’annullamento o la revoca:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno o più dei motivi elencati all’articolo 12, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la richiesta di revoca del visto presentata dal titolare.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 14 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elemento di frase introduttivo è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Qualora sia adottata una decisione di proroga del periodo di validità e/o della durata del soggiorno per un visto rilasciato, l’autorità competente per i visti che ha prorogato il visto aggiunge al fascicolo i seguenti dati:»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera d) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di vignetta visto del visto prorogato;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera g) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">zona geografica all’interno della quale il titolare del visto è autorizzato a spostarsi, se la validità territoriale del visto prorogato è diversa da quella del visto originario;»</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, la lettera c) è soppressa;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 15, paragrafo 1, i termini «proroga o riduzione della validità dei visti» sono sostituiti dai termini: «o proroga dei visti»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 17 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 4 è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Stato membro del primo ingresso;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 6 è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo di visto rilasciato;»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 11 è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">scopo/i principale/i del viaggio;»</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 18, paragrafo 4, lettera c), all’articolo 19, paragrafo 2, lettera c), all’articolo 20, paragrafo 2, lettera d), all’articolo 22, paragrafo 2, lettera d), i termini «o ridotta» sono soppressi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 23, paragrafo 1, lettera d), il termine «ridotto» è soppresso.</p>\n</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Abrogazioni", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli articoli da 9 a 17 della convenzione di applicazione dell’accordo di Schengen del 14 giugno 1985 sono abrogati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono abrogati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la decisione del comitato esecutivo Schengen del 28 aprile 1999 riguardante le versioni definitive del manuale comune e dell’istruzione consolare comune [SCH/Com-ex (99)13 — Istruzione consolare comune, compresi gli allegati];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le decisioni del comitato esecutivo Schengen del 14 dicembre 1993 riguardanti la proroga del visto uniforme [SCH/Com-ex (93) 21] e le procedure comuni relative all’annullamento, alla revoca e alla riduzione della validità del visto uniforme [SCH/Com-ex (93) 24], la decisione del comitato esecutivo Schengen del 22 dicembre 1994 riguardante lo scambio di dati statistici relativi al rilascio di visti uniformi [SCH/Com-ex (94) 25], la decisione del comitato esecutivo Schengen del 21 aprile 1998 riguardante lo scambio a livello locale di dati statistici relativi ai visti [SCH/Com-ex (98) 12], e la decisione del comitato esecutivo Schengen del 16 dicembre 1998 relativa all’introduzione di un documento uniforme quale giustificativo di un invito, di una dichiarazione di garanzia o di un certificato recante l’impegno a fornire ospitalità [SCH/Com-ex (98) 57];</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’azione comune 96/197/GAI, del 4 marzo 1996, sul regime di transito aeroportuale (\n<span class=\"superscript\">14</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il regolamento (CE) n. 789/2001 del Consiglio, del 24 aprile 2001, che conferisce al Consiglio competenze esecutive per quanto concerne talune disposizioni dettagliate e modalità pratiche relative all’esame delle domande di visto (\n<span class=\"superscript\">15</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il regolamento (CE) n. 1091/2001 del Consiglio, del 28 maggio 2001, relativo alla libera circolazione dei titolari di un visto per soggiorno di lunga durata (\n<span class=\"superscript\">16</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il regolamento (CE) n. 415/2003 del Consiglio, del 27 febbraio 2003, relativo al rilascio di visti alla frontiera, compreso il rilascio di visti a marittimi in transito (\n<span class=\"superscript\">17</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 2 del regolamento (CE) n. 390/2009 del Parlamento europeo e del Consiglio, del 23 aprile 2009, recante modifica dell’istruzione consolare comune diretta alle rappresentanze diplomatiche e consolari di prima categoria in relazione all’introduzione di elementi biometrici e comprendente norme sull’organizzazione del ricevimento e del trattamento delle domande di visto (\n<span class=\"superscript\">18</span>\n).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I riferimenti a strumenti abrogati sono intesi come riferimenti al presente regolamento e vanno letti secondo la tavola di concordanza di cui all’allegato XIII.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Monitoraggio e valutazione", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Due anni dopo che tutte le disposizioni del presente regolamento sono diventate applicabili, la Commissione presenta una valutazione della sua applicazione. Tale valutazione globale include un esame dei risultati ottenuti rispetto agli obiettivi e dell’attuazione delle disposizioni del presente regolamento fatte salve le relazioni di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette la valutazione di cui al paragrafo 1 al Parlamento europeo e al Consiglio. Sulla base di tale valutazione la Commissione presenta, se del caso, opportune proposte di modifica del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Tre anni dopo l’entrata in funzione del VIS e in seguito ogni quattro anni, la Commissione trasmette al Parlamento europeo e al Consiglio una relazione sull’attuazione degli articoli 13, 17, da 40 a 44 del presente regolamento, che riferisce circa l’attuazione della raccolta e dell’uso degli identificatori biometrici, l’idoneità della norma ICAO scelta, la conformità con le norme sulla protezione dei dati, l’esperienza con i fornitori esterni di servizi con un particolare riferimento alla raccolta dei dati biometrici, l’attuazione della regola dei cinquantanove mesi per copiare le impronte digitali e l’organizzazione delle procedure relative alle domande. La relazione include inoltre, in base all’articolo 17, paragrafi 12, 13 e 14, e all’articolo 50, paragrafo 4, del regolamento VIS, i casi in cui non è stato possibile fornire le impronte digitali per ragioni di fatto o non era obbligatorio fornirle per motivi giuridici, rispetto al numero di casi in cui le impronte digitali erano state rilevate. La relazione include informazioni sui casi di rifiuto del visto a persone che non hanno potuto fornire le impronte digitali per ragioni di fatto. La relazione è corredata, se del caso, di adeguate proposte di modifica del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La prima delle relazioni di cui al paragrafo 3 riguarda altresì il problema della sufficiente affidabilità ai fini dell’identificazione e verifica delle impronte digitali di bambini di età inferiore a dodici anni e, in particolare, il modo in cui le impronte digitali evolvono con l’età, in base ai risultati di una ricerca effettuata sotto la responsabilità della Commissione.</div>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Entrata in vigore", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Esso si applica a decorrere dal 5 aprile 2010.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’articolo 52 e l’articolo 53, paragrafo 1, lettere da a) ad h), e paragrafo 2, si applicano a decorrere dal 5 ottobre 2009.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda la rete di consultazione Schengen (specifiche tecniche), l’articolo 56, paragrafo 2, lettera d), si applica dalla data di cui all’articolo 46 del regolamento VIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’articolo 32, paragrafi 2 e 3, l’articolo 34, paragrafi 6 e 7, e l’articolo 35, paragrafo 7, si applicano a decorrere dal 5 aprile 2011.</div>\n</div>"]]}}, "recitals": {}};